INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Cuarto Grado', 'Ciencias Sociales', '1. Compara la relación dinámica de los procesos formadores de la tierra en Guatemala y Centroamérica con la configuración de su superficie.', ARRAY['1.1. Describe los procesos de formación de la tierra y su relación con la ubicación geográfica de Centroamérica.', '1.2. Describe los riesgos de vivir en zonas vulnerables a las fallas geológicas.', '1.3. Describe la incidencia que tiene el relieve en los climas y en la vida de las personas.']),
('Cuarto Grado', 'Ciencias Sociales', '2. Describe las relaciones que se dan entre diversas formas de vida y el ambiente natural.', ARRAY['2.1. Explica los distintos elementos de las cosmovisiones de los pueblos de Guatemala.', '2.2. Describe las riquezas naturales con las que cuenta Centroamérica, las formas de aprovechamiento y de conservación.']),
('Cuarto Grado', 'Ciencias Sociales', '3. Relaciona la ubicación geográfica de los países centroamericanos con la distribución, el desplazamiento y las actividades productivas de la población.', ARRAY['3.1. Identifica los procesos sociales relacionados con la vida, el aumento y la disminución de la población centroamericana.', '3.2. Describe distintas actividades económicas y productivas que se dan en los diferentes países de Centroamérica.', '3.3. Describe las acciones que realizan las instituciones y las organizaciones que impulsan la integración económica de Centroamérica.']),
('Cuarto Grado', 'Ciencias Sociales', '4. Describe los espacios y escenarios de la cotidianidad en su comunidad y la relación con otros países de Centroamérica.', ARRAY['4.1. Describe las distintas prácticas que se dan en su comunidad y otras comunidades de los países centroamericanos.', '4.2. Describe los espacios y escenarios que se dan en la cotidianidad en su comunidad.', '4.3. Identifica instituciones sociales, político-administrativas y religiosas de Centroamérica.']),
('Cuarto Grado', 'Ciencias Sociales', '5. Utiliza la curiosidad, la experiencia personal y los saberes de su comunidad como medios de aprendizaje.', ARRAY['5.1. Utiliza la observación y el registro de información como medio de aprendizaje.']),
('Cuarto Grado', 'Ciencias Sociales', '6. Relaciona hechos actuales de Centroamérica con acontecimientos históricos.', ARRAY['6.1. Relaciona la historia de los pueblos primitivos de su país y la de los pueblos primitivos en los otros países que integran la región centroamericana.', '6.2. Establece la relación entre los principales procesos históricos que ha vivido la región centroamericana, a partir del descubrimiento, conquista y colonización.', '6.3. Relaciona diferentes hechos y situaciones que se manifiestan durante la época colonial en Centroamérica.', '6.4. Describe el proceso de independencia de Centroamérica, resaltando los intereses que promovieron la participación de los diferentes grupos sociales.', '6.5. Establece la relación entre los principales acontecimientos que se manifiestan durante el siglo XIX y los efectos en el ámbito social, económico, político y cultural de cada país centroamericano.', '6.6. Identifica los principales acontecimientos ocurridos en el siglo XX.']),
('Cuarto Grado', 'Ciencias Sociales', '7. Practica valores, hábitos y actitudes que fomentan el respeto, la tolerancia, la solidaridad y otros valores en su vida diaria.', ARRAY['7.1. Practica sus derechos y cumple con sus responsabilidades en la familia, escuela y comunidad.', '7.2. Manifiesta sentido de pertenencia a la región centroamericana.']),
('Cuarto Grado', 'Ciencias Sociales', '8. Identifica distintas opciones de solución a los problemas y conflictos políticos y sociales de Centroamérica.', ARRAY['8.1. Utiliza el diálogo como medio de comunicación para la solución de conflictos.', '8.2. Relaciona condiciones que determinan la calidad de vida de los habitantes de Centroamérica.', '8.3. Identifica sus responsabilidades ciudadanas y los organismos que velan por los Derechos Humanos en el país.']);
